class SecureSessionManager(private val context: android.content.Context) {
    
    private val prefs = context.getSharedPreferences("secure_session", android.content.Context.MODE_PRIVATE)
    private val ENCRYPTED_TOKEN_KEY = "encrypted_token"
    private val IV_KEY = "iv"
    private val SESSION_TIMESTAMP = "session_timestamp"
    private val SESSION_TIMEOUT = 30 * 60 * 1000L
    
    private var currentSessionToken: String? = null

    fun createSecureSession(sessionToken: String, cipher: Cipher) {
        try {
            val encryptedToken = cipher.doFinal(sessionToken.toByteArray())
            val iv = cipher.iv

            prefs.edit().apply {
                putString(ENCRYPTED_TOKEN_KEY, android.util.Base64.encodeToString(encryptedToken, android.util.Base64.DEFAULT))
                putString(IV_KEY, android.util.Base64.encodeToString(iv, android.util.Base64.DEFAULT))
                putLong(SESSION_TIMESTAMP, System.currentTimeMillis())
                apply()
            }

            currentSessionToken = sessionToken
        } catch (e: Exception) {
            e.printStackTrace()
        }
    }

    fun createPasswordBasedSession(sessionToken: String) {
        prefs.edit().apply {
            putLong(SESSION_TIMESTAMP, System.currentTimeMillis())
            apply()
        }
        currentSessionToken = sessionToken
    }

    fun hasValidSession(): Boolean {
        val timestamp = prefs.getLong(SESSION_TIMESTAMP, 0)
        val isValid = timestamp > 0 && (System.currentTimeMillis() - timestamp) < SESSION_TIMEOUT
        
        return isValid && currentSessionToken != null
    }

    fun clearSession() {
        prefs.edit().clear().apply()
        currentSessionToken = null
    }

    fun getSessionToken(): String? {
        return if (hasValidSession()) currentSessionToken else null
    }
}

